import React, { useState, useEffect } from 'react';
import { useLocation, useNavigate } from 'react-router-dom';

import AnnotationTopBar from '../components/AnnotationTopBar';
import AnnotationCanvas from '../components/AnnotationCanvas';
import AnnotationListSidebar from '../components/AnnotationListSidebar';
import './Annotate.css';

// NEW: import polygon-clipping
import polygonClipping from 'polygon-clipping';

export default function Annotate() {
  const navigate = useNavigate();
  const { state } = useLocation();
  const folderInfo = state?.folderInfo;

  if (!folderInfo) {
    return (
      <div style={{ padding: 20 }}>
        <h2>No folder info found. Please create a task first.</h2>
        <button onClick={() => navigate('/')}>Go Home</button>
      </div>
    );
  }

  const { folderId, taskName, labelClasses, files } = folderInfo;

  // -------------- Annotations for each image --------------
  const [annotations, setAnnotations] = useState({});
  const [undoStack, setUndoStack] = useState([]);
  const [redoStack, setRedoStack] = useState([]);
  const [currentIndex, setCurrentIndex] = useState(0);

  // Tools: move, bbox, polygon, polyline, point, ellipse, segmentation
  // default to 'move'
  const [selectedTool, setSelectedTool] = useState('move');

  // For “segmentation” specifically, we have a small dropdown (Instance, Semantic, Panoptic)
  const [segmentationType, setSegmentationType] = useState('instance');

  const [selectedLabelClass, setSelectedLabelClass] = useState(
    labelClasses[0]?.name || ''
  );
  const [scale, setScale] = useState(1.0);

  const currentFileUrl = files[currentIndex]?.url;
  const currentShapes = annotations[currentFileUrl] || [];

  // Whenever shapes change, store old state in undoStack
  const handleAnnotationsChange = (newShapes) => {
    const updated = {
      ...annotations,
      [currentFileUrl]: newShapes,
    };
    setUndoStack([...undoStack, annotations]);
    setRedoStack([]);
    setAnnotations(updated);
  };

  // -------------- Undo / Redo --------------
  const undo = () => {
    if (undoStack.length === 0) return;
    const prev = undoStack[undoStack.length - 1];
    setRedoStack([...redoStack, annotations]);
    setUndoStack(undoStack.slice(0, -1));
    setAnnotations(prev);
  };

  const redo = () => {
    if (redoStack.length === 0) return;
    const next = redoStack[redoStack.length - 1];
    setUndoStack([...undoStack, annotations]);
    setRedoStack(redoStack.slice(0, -1));
    setAnnotations(next);
  };

  // -------------- Deletion & Update --------------
  const handleDeleteAnnotation = (index) => {
    const arr = [...currentShapes];
    arr.splice(index, 1);
    handleAnnotationsChange(arr);
  };

  const handleUpdateAnnotation = (index, changes) => {
    const arr = [...currentShapes];
    arr[index] = { ...arr[index], ...changes };
    handleAnnotationsChange(arr);
  };

  // -------------- Navigation --------------
  const handlePrev = () => {
    if (currentIndex > 0) setCurrentIndex((i) => i - 1);
  };
  const handleNext = () => {
    if (currentIndex < files.length - 1) setCurrentIndex((i) => i + 1);
  };

  // -------------- Zoom --------------
  const handleZoomIn = () => setScale((s) => Math.min(s + 0.1, 5));
  const handleZoomOut = () => setScale((s) => Math.max(s - 0.1, 0.2));
  const handleWheelZoom = (deltaY) => {
    if (deltaY < 0) handleZoomIn();
    else handleZoomOut();
  };

  // -------------- Save --------------
  const handleSave = async () => {
    const bodyData = {
      folderId,
      taskName,
      labelClasses,
      annotations,
    };
    try {
      const res = await fetch('http://localhost:4000/api/annotations', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(bodyData),
      });
      const data = await res.json();
      alert('Saved: ' + data.message);
    } catch (err) {
      console.error(err);
      alert('Error saving');
    }
  };

  // -------------- Keyboard Shortcuts --------------
  useEffect(() => {
    const handleKey = (e) => {
      const key = e.key;

      // Tools
      if (key === 'm' || key === 'M') {
        setSelectedTool('move');
      } else if (key === 'b' || key === 'B') {
        setSelectedTool('bbox');
      } else if (key === 'p' || key === 'P') {
        setSelectedTool('polygon');
      } else if (key === 'l' || key === 'L') {
        setSelectedTool('polyline');
      } else if (key === 'o' || key === 'O') {
        setSelectedTool('point');
      } else if (key === 'e' || key === 'E') {
        setSelectedTool('ellipse');
      }
      // Segmentation on plain "S"
      else if ((key === 's' || key === 'S') && e.ctrlKey) {
        // Ctrl+S => Save
        e.preventDefault();
        handleSave();
      } else if (key === 's' || key === 'S') {
        // Just S => Segmentation
        setSelectedTool('segmentation');
      }

      // Esc => cancel shape
      if (key === 'Escape') {
        const event = new CustomEvent('cancel-annotation');
        window.dispatchEvent(event);
      }
      // Next / Prev
      if (key === 'ArrowRight') {
        handleNext();
      } else if (key === 'ArrowLeft') {
        handlePrev();
      }

      // Undo / Redo
      if (e.ctrlKey && (key === 'z' || key === 'Z')) {
        e.preventDefault();
        undo();
      } else if (e.ctrlKey && (key === 'y' || key === 'Y')) {
        e.preventDefault();
        redo();
      }
    };
    window.addEventListener('keydown', handleKey);
    return () => window.removeEventListener('keydown', handleKey);
    // eslint-disable-next-line
  }, [annotations, undoStack, redoStack]);

  // -------------- Export Logic --------------
  const [exportOpen, setExportOpen] = useState(false);
  const openExport = () => setExportOpen(true);
  const closeExport = () => setExportOpen(false);

  const exportAnnotations = (format) => {
    if (format === 'coco') {
      downloadCOCO();
    } else if (format === 'yolo') {
      downloadYOLO();
    } else if (format === 'pascal') {
      downloadPascal();
    }
    closeExport();
  };

  function downloadFile(url, filename) {
    const a = document.createElement('a');
    a.href = url;
    a.download = filename;
    a.click();
    URL.revokeObjectURL(url);
  }

  function downloadCOCO() {
    alert('COCO export not yet implemented!');
  }
  function downloadYOLO() {
    alert('YOLO export not yet implemented!');
  }
  function downloadPascal() {
    alert('Pascal VOC export not yet implemented!');
  }

  // -------------- When annotation finishes => switch to move --------------
  const handleFinishShape = () => {
    setSelectedTool('move');
  };

  // ------------------------------------------------------------------------
  // NEW STATES & FUNCTIONS FOR "FILL EMPTY SPACES" with HOLES
  // ------------------------------------------------------------------------
  const [backgroundLabelName, setBackgroundLabelName] = useState('background');
  const [backgroundColor, setBackgroundColor] = useState('#000000');

  // Ensure black is not already used by label classes. If it is, pick something else
  const ensureBackgroundColorUnique = () => {
    const usedColors = labelClasses.map((lc) => lc.color.toLowerCase());
    if (usedColors.includes(backgroundColor.toLowerCase())) {
      // pick a simple fallback, e.g. #111111
      setBackgroundColor('#111111');
    }
  };

  // Helper: approximate ellipse as polygon
  const approximateEllipse = (ellipse, numPoints = 20) => {
    const { x, y, radiusX, radiusY } = ellipse;
    const ring = [];
    for (let i = 0; i < numPoints; i++) {
      const theta = (2 * Math.PI * i) / numPoints;
      const px = x + radiusX * Math.cos(theta);
      const py = y + radiusY * Math.sin(theta);
      ring.push([px, py]);
    }
    // close the ring
    ring.push(ring[0]);
    return ring;
  };

  // Convert coverage shapes (bbox, ellipse, polygon) into polygon-clipping format
  const convertCoverageShapesToPolygons = (shapes) => {
    const coveragePolys = [];
    shapes.forEach((ann) => {
      if (ann.type === 'polygon') {
        // ann.points = [{x, y}, ...]
        const ring = ann.points.map((p) => [p.x, p.y]);
        // close ring if needed
        if (
          ring.length > 2 &&
          (ring[0][0] !== ring[ring.length - 1][0] ||
            ring[0][1] !== ring[ring.length - 1][1])
        ) {
          ring.push(ring[0]);
        }
        coveragePolys.push([ring]);
      } else if (ann.type === 'bbox') {
        // x, y, width, height
        const x1 = ann.x;
        const y1 = ann.y;
        const x2 = ann.x + ann.width;
        const y2 = ann.y + ann.height;
        const ring = [
          [x1, y1],
          [x2, y1],
          [x2, y2],
          [x1, y2],
          [x1, y1],
        ];
        coveragePolys.push([ring]);
      } else if (ann.type === 'ellipse') {
        // approximate
        const ring = approximateEllipse(ann, 24);
        coveragePolys.push([ring]);
      }
      // polyline, points, point => ignore (not filled)
    });
    return coveragePolys;
  };

  // MAIN function to fill empty spaces => produce ONE multipolygon annotation with holes
  const handleFillEmptySpaces = () => {
    // Only relevant if we're doing segmentation: instance, semantic, or panoptic
    if (
      selectedTool !== 'segmentation' ||
      !['instance', 'semantic', 'panoptic'].includes(segmentationType)
    ) {
      return;
    }
    if (!currentFileUrl) return;

    // 1) check color uniqueness
    ensureBackgroundColorUnique();

    // 2) Load the actual image to get width & height
    const img = new window.Image();
    img.src = currentFileUrl;
    img.onload = () => {
      const w = img.width;
      const h = img.height;

      // Convert existing coverage shapes
      const coverageShapes = convertCoverageShapesToPolygons(currentShapes);
      let unionOfCoverage = [];
      if (coverageShapes.length > 0) {
        try {
          unionOfCoverage = polygonClipping.union(...coverageShapes);
        } catch (err) {
          console.error('Union error', err);
          alert('Could not union existing coverage shapes.');
          return;
        }
      }

      // The entire image as one big polygon
      const imagePoly = [
        [
          [0, 0],
          [w, 0],
          [w, h],
          [0, h],
          [0, 0],
        ],
      ];

      // 3) Subtract coverage from entire image => result is "background" with holes
      let differenceResult;
      if (!unionOfCoverage || unionOfCoverage.length === 0) {
        // If no coverage at all, entire image is background
        differenceResult = [imagePoly];
      } else {
        try {
          differenceResult = polygonClipping.difference(imagePoly, unionOfCoverage);
          // differenceResult can be null or array
          if (!differenceResult || differenceResult.length === 0) {
            alert('No empty space found!');
            return;
          }
        } catch (err) {
          console.error('Difference error', err);
          alert('Could not compute empty space polygons.');
          return;
        }
      }

      // differenceResult is an array of polygons; each polygon is an array-of-rings
      // For "one background annotation with holes," we'll store them all in a single
      // annotation of type "multipolygon."
      // We are ignoring the possibility that differenceResult might have multiple polygons
      // that are disjoint; they will be rendered as disjoint shapes in one annotation.

      const newBackgroundAnnotation = {
        type: 'multipolygon',
        label: backgroundLabelName,
        color: backgroundColor,
        polygons: differenceResult, // store raw polygons (each has rings)
      };

      // 4) Insert that single annotation
      const merged = [...currentShapes, newBackgroundAnnotation];
      handleAnnotationsChange(merged);

      alert(
        `Filled empty spaces with 1 background annotation (may contain multiple disjoint regions or holes).`
      );
    };
  };
  // ------------------------------------------------------------------------

  return (
    <div className="annotate-container">
      <AnnotationTopBar
        onHome={() => navigate('/')}
        onPrev={handlePrev}
        onNext={handleNext}
        onSave={handleSave}
        onZoomIn={handleZoomIn}
        onZoomOut={handleZoomOut}
        onExport={openExport}
        currentIndex={currentIndex}
        total={files.length}
        taskName={taskName}
      />

      <div style={{ padding: '8px', background: '#eee' }}>
        <button onClick={undo} style={{ marginRight: '8px' }}>
          Undo (Ctrl+Z)
        </button>
        <button onClick={redo} style={{ marginRight: '8px' }}>
          Redo (Ctrl+Y)
        </button>
      </div>

      <div className="annotate-main">
        {/* Tools Sidebar */}
        <div className="tools-sidebar">
          <h3>Tools</h3>
          <label>
            <input
              type="radio"
              name="tool"
              value="move"
              checked={selectedTool === 'move'}
              onChange={() => setSelectedTool('move')}
            />
            <span className="tool-icon">👆</span> Move (M)
          </label>
          <label>
            <input
              type="radio"
              name="tool"
              value="bbox"
              checked={selectedTool === 'bbox'}
              onChange={() => setSelectedTool('bbox')}
            />
            <span className="tool-icon">⬛</span> BBox (B)
          </label>
          <label>
            <input
              type="radio"
              name="tool"
              value="polygon"
              checked={selectedTool === 'polygon'}
              onChange={() => setSelectedTool('polygon')}
            />
            <span className="tool-icon">🔺</span> Polygon (P)
          </label>
          <label>
            <input
              type="radio"
              name="tool"
              value="polyline"
              checked={selectedTool === 'polyline'}
              onChange={() => setSelectedTool('polyline')}
            />
            <span className="tool-icon">📈</span> Polyline (L)
          </label>
          <label>
            <input
              type="radio"
              name="tool"
              value="point"
              checked={selectedTool === 'point'}
              onChange={() => setSelectedTool('point')}
            />
            <span className="tool-icon">📍</span> Point (O)
          </label>
          <label>
            <input
              type="radio"
              name="tool"
              value="ellipse"
              checked={selectedTool === 'ellipse'}
              onChange={() => setSelectedTool('ellipse')}
            />
            <span className="tool-icon">⬭</span> Ellipse (E)
          </label>

          {/* Segmentation */}
          <label>
            <input
              type="radio"
              name="tool"
              value="segmentation"
              checked={selectedTool === 'segmentation'}
              onChange={() => setSelectedTool('segmentation')}
            />
            <span className="tool-icon">🎨</span> Segmentation (S)
          </label>
          {selectedTool === 'segmentation' && (
            <div style={{ marginLeft: '20px', marginBottom: '8px' }}>
              <label style={{ display: 'block', marginBottom: '4px' }}>
                Type:
              </label>
              <select
                value={segmentationType}
                onChange={(e) => setSegmentationType(e.target.value)}
              >
                <option value="instance">Instance</option>
                <option value="semantic">Semantic</option>
                <option value="panoptic">Panoptic</option>
              </select>
            </div>
          )}

          <h3 style={{ marginTop: 16 }}>Active Label</h3>
          <select
            value={selectedLabelClass}
            onChange={(e) => setSelectedLabelClass(e.target.value)}
          >
            {labelClasses.map((lc, i) => (
              <option key={i} value={lc.name}>
                {lc.name}
              </option>
            ))}
          </select>

          {/* NEW: Fill Empty Spaces (only for segmentation) */}
          {selectedTool === 'segmentation' &&
            ['instance', 'semantic', 'panoptic'].includes(segmentationType) && (
              <div style={{ marginTop: 16, padding: '8px', background: '#f8f8f8', border: '1px solid #ccc' }}>
                <h4 style={{ margin: '4px 0' }}>Fill Background</h4>
                <div style={{ marginBottom: 8 }}>
                  <label style={{ fontSize: '0.9rem' }}>
                    Label Name:&nbsp;
                    <input
                      type="text"
                      value={backgroundLabelName}
                      onChange={(e) => setBackgroundLabelName(e.target.value)}
                      style={{ width: 110, padding: 2, fontSize: '0.9rem' }}
                    />
                  </label>
                </div>
                <div style={{ marginBottom: 8 }}>
                  <label style={{ fontSize: '0.9rem' }}>
                    Color:&nbsp;
                    <input
                      type="color"
                      value={backgroundColor}
                      onChange={(e) => setBackgroundColor(e.target.value)}
                      style={{ width: 40, height: 24, verticalAlign: 'middle' }}
                    />
                  </label>
                </div>
                <button
                  onClick={handleFillEmptySpaces}
                  style={{
                    padding: '4px 8px',
                    fontSize: '0.9rem',
                    cursor: 'pointer',
                    background: '#ddd',
                    border: '1px solid #aaa',
                    borderRadius: 4
                  }}
                >
                  Fill Empty Spaces
                </button>
              </div>
            )}

          <div className="note-area" style={{ marginTop: 16 }}>
            <p><strong>Shortcuts:</strong></p>
            <ul style={{ margin: 0, paddingLeft: 20 }}>
              <li>M/B/P/L/O/E => Tools</li>
              <li>S => Segmentation</li>
              <li>Ctrl+S => Save</li>
              <li>Esc => Cancel shape</li>
              <li>ArrowLeft => Prev image</li>
              <li>ArrowRight => Next image</li>
              <li>Ctrl+Z => Undo</li>
              <li>Ctrl+Y => Redo</li>
              <li>Ctrl+C => Copy selected</li>
              <li>Ctrl+V => Paste annotation</li>
            </ul>
          </div>
        </div>

        {/* Canvas */}
        <div className="canvas-area">
          {currentFileUrl ? (
            <AnnotationCanvas
              fileUrl={currentFileUrl}
              annotations={currentShapes}
              onAnnotationsChange={handleAnnotationsChange}
              selectedTool={selectedTool}
              scale={scale}
              onWheelZoom={handleWheelZoom}
              activeLabelColor={
                labelClasses.find((l) => l.name === selectedLabelClass)?.color ||
                '#ff0000'
              }
              onFinishShape={handleFinishShape}
              onDeleteAnnotation={handleDeleteAnnotation}
              activeLabel={selectedLabelClass}
              labelClasses={labelClasses}
              // Pass segmentationType to the canvas
              segmentationType={segmentationType}
            />
          ) : (
            <div style={{ textAlign: 'center', margin: 'auto' }}>
              No images found
            </div>
          )}
        </div>

        <AnnotationListSidebar
          annotations={currentShapes}
          onDeleteAnnotation={handleDeleteAnnotation}
          onUpdateAnnotation={handleUpdateAnnotation}
          labelClasses={labelClasses}
        />
      </div>

      {exportOpen && (
        <div className="export-modal-backdrop">
          <div className="export-modal">
            <h2>Export Annotations</h2>
            <p>Select format:</p>
            <div className="export-buttons">
              <button onClick={() => exportAnnotations('coco')}>COCO</button>
              <button onClick={() => exportAnnotations('yolo')}>YOLO</button>
              <button onClick={() => exportAnnotations('pascal')}>Pascal VOC</button>
            </div>
            <button className="close-btn" onClick={closeExport}>
              Close
            </button>
          </div>
        </div>
      )}
    </div>
  );
}
